/* General Styles */
body {
  font-family: 'Arial', sans-serif;
  background-color: #f4f4f4;
  color: #333;
  margin: 0;
  padding: 0;
}

/* CSS for project container */
.project-container {
  display: flex; /* Use flexbox for layout */
  flex-wrap: wrap; /* Allow wrapping of items */
  justify-content: space-around; /* Space items evenly */
  margin: 20px 0; /* Add vertical margin */
}

/* CSS for project cards */
.project {
  background: #f9f9f9; /* Card background color */
  border: 1px solid #ddd; /* Card border */
  border-radius: 10px; /* Rounded corners */
  margin: 10px; /* Space between cards */
  padding: 15px; /* Inner padding */
  flex: 1 1 300px; /* Grow to fill space, but start at a base width of 300px */
  /*max-width: 300px;  Set a maximum width */
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.1); /* Optional shadow effect */
  transition: transform 0.2s; /* Smooth hover effect */
}

/* Optional hover effect */
.project:hover {
  transform: scale(1.02); /* Slightly enlarge the card on hover */
}

/* CSS for project images */
.project img {
  width: 100%; /* Make images responsive */
  height: auto; /* Maintain aspect ratio */
  border-radius: 10px; /* Match card corners */
}



.content {
  max-width: 1200px;
  margin: 0 auto;
  padding: 20px;
}

/* Projects Section */
.projects-section {
  margin-bottom: 40px;
}

.section-title {
  font-size: 1.8em;
  color: #444;
  margin-bottom: 20px;
}

.project-card {
  display: flex;
  background-color: #fff;
  margin-bottom: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
  overflow: hidden;
  transition: transform 0.3s ease;
}

.project-card:hover {
  transform: scale(1.02);
}

.project-image {
  width: 150px;
  height: auto;
  object-fit: cover;
}

.project-content {
  padding: 20px;
  flex: 1;
}

.project-content h3 {
  margin-top: 0;
  font-size: 1.4em;
}

.project-summary {
  color: #666;
}

.read-more-btn {
  background-color: #007BFF;
  color: #fff;
  border: none;
  padding: 10px 20px;
  cursor: pointer;
  border-radius: 4px;
  font-size: 0.9em;
  transition: background-color 0.3s ease;
}

.read-more-btn:hover {
  background-color: #0056b3;
}

.navigation-tip {
  font-size: 0.9em;
  color: #888;
}


